from typing import Optional, Dict
from abc import ABC, abstractmethod
from uuid import uuid4

class UserRepository(ABC):
    @abstractmethod
    def save(self, user: "User") -> "User": ...
    @abstractmethod
    def find_by_id(self, user_id: str) -> Optional["User"]: ...
    @abstractmethod
    def find_by_email(self, email: str) -> Optional["User"]: ...

class FakeUserRepository(UserRepository):
    def __init__(self) -> None:
        self.users: Dict[str, "User"] = {}
        self.email_index: Dict[str, str] = {}

    def save(self, user: "User") -> "User":
        if not user.id:
            user.id = str(uuid4())
        self.users[user.id] = user
        self.email_index[user.email] = user.id
        return user

    def find_by_id(self, user_id: str) -> Optional["User"]:
        return self.users.get(user_id)

    def find_by_email(self, email: str) -> Optional["User"]:
        uid = self.email_index.get(email)
        return self.users.get(uid) if uid else None

import { jest, describe, it, expect, beforeEach } from '@jest/globals';

const mockUserRepository = {
  save: jest.fn(),
  findById: jest.fn(),
  findByEmail: jest.fn(),
};

describe('UserService', () => {
  beforeEach(() => { jest.clearAllMocks(); });

  it('should create user and return with id', async () => {
    const userData = { email: 'test@example.com', name: 'Test' };
    mockUserRepository.save.mockResolvedValue({ id: '123', ...userData });
    const service = new UserService(mockUserRepository as any);
    const result = await service.createUser(userData);
    expect(result.id).toBe('123');
    expect(mockUserRepository.save).toHaveBeenCalledWith(
      expect.objectContaining({ email: 'test@example.com' })
    );
  });
});
